class RateLimiter:
    """Per-IP rate limiter to prevent query flooding."""

    def __init__(self, window: int, max_requests: int):
        self.window = window
        self.max_requests = max_requests
        self.requests = defaultdict(list)

    def is_allowed(self, ip: str) -> bool:
        now = time.time()
        # Clean old entries
        self.requests[ip] = [
            t for t in self.requests[ip] if now - t < self.window
        ]
        if len(self.requests[ip]) >= self.max_requests:
            return False
        self.requests[ip].append(now)
        return True

    def cleanup(self):
        """Periodically remove stale entries."""
        now = time.time()
        stale_ips = [
            ip for ip, times in self.requests.items()
            if not times or now - times[-1] > self.window * 2
        ]
        for ip in stale_ips:
            del self.requests[ip]


class ChallengeManager:
    """Challenge-response system to verify client IP addresses (anti-spoofing)."""

    def __init__(self, secret: bytes, expiry: int):
        self.secret = secret
        self.expiry = expiry

    def generate_challenge(self, addr: tuple) -> bytes:
        """Generate a challenge token tied to the client address and current time window."""
        time_window = int(time.time()) // self.expiry
        data = f"{addr[0]}:{addr[1]}:{time_window}".encode() + self.secret
        return hashlib.sha256(data).digest()[:8]

    def verify_challenge(self, addr: tuple, token: bytes) -> bool:
        """Verify a challenge token, checking current and previous time window."""
        for offset in (0, -1):
            time_window = int(time.time()) // self.expiry + offset
            data = f"{addr[0]}:{addr[1]}:{time_window}".encode() + self.secret
            expected = hashlib.sha256(data).digest()[:8]
            if token == expected:
                return True
        return False


# Protocol message types
MSG_CHALLENGE_REQUEST = 0x01  # Client -> Server: request a challenge
MSG_CHALLENGE_RESPONSE = 0x02  # Server -> Client: here's your challenge token
MSG_STATUS_REQUEST = 0x03  # Client -> Server: status query with challenge token
MSG_STATUS_RESPONSE = 0x04  # Server -> Client: status data
MSG_STATUS_COMPACT = 0x05  # Server -> Client: compact status (truncated)
MSG_ERROR = 0xFF

# Protocol header: 4-byte magic + 1-byte message type
MAGIC = b"\xff\xffGS"


def build_compact_status() -> bytes:
    """Build a compact status response that fits within size limits."""
    compact = {
        "name": game_state["server_name"][:32],
        "map": game_state["map"][:16],
        "mode": game_state["game_mode"][:16],
        "players": len(game_state["players"]),
        "max": game_state["max_players"],
        "ver": game_state["version"],
    }
    return json.dumps(compact, separators=(",", ":")).encode("utf-8")


def build_full_status() -> bytes:
    """Build full status JSON."""
    status = {
        "server_name": game_state["server_name"],
        "map": game_state["map"],
        "game_mode": game_state["game_mode"],
        "player_count": len(game_state["players"]),
        "max_players": game_state["max_players"],
        "version": game_state["version"],
        "players": [
            {
                "name": p["name"],
                "score": p["score"],
                "ping": p["ping"],
                "team": p["team"],
            }
            for p in game_state["players"]
        ],
    }
    return json.dumps(status, separators=(",", ":")).encode("utf-8")


def build_paginated_status(page: int, page_size: int = 8) -> bytes:
    """Build a paginated status response to keep response sizes bounded."""
    players = game_state["players"]
    total_pages = max(1, (len(players) + page_size - 1) // page_size)
    page = max(0, min(page, total_pages - 1))

    start = page * page_size
    end = start + page_size
    page_players = players[start:end]

    status = {
        "server_name": game_state["server_name"],
        "map": game_state["map"],
        "game_mode": game_state["game_mode"],
        "player_count": len(players),
        "max_players": game_state["max_players"],
        "version": game_state["version"],
        "page": page,
        "total_pages": total_pages,
        "players": [
            {
                "name": p["name"],
                "score": p["score"],
                "ping": p["ping"],
                "team": p["team"],
            }
            for p in page_players
        ],
    }
    return json.dumps(status, separators=(",", ":")).encode("utf-8")


def make_response(msg_type: int, payload: bytes) -> bytes:
    """Construct a protocol response packet."""
    return MAGIC + struct.pack("B", msg_type) + payload


def make_error(message: str) -> bytes:
    """Construct an error response."""
    return make_response(MSG_ERROR, message.encode("utf-8")[:64])


def handle_packet(
    data: bytes,
    addr: tuple,
    rate_limiter: RateLimiter,
    challenge_mgr: ChallengeManager,
) -> bytes | None:
    """
    Process an incoming UDP packet and return a response (or None to drop).

    Anti-amplification measures:
    1. Challenge-response: clients must first obtain a challenge token, proving
       their IP is not spoofed, before they can get status data.
    2. Rate limiting: per-IP request throttling.
    3. Response size capping: responses are kept small; full player lists are
       paginated so no single response greatly exceeds the request size.
    4. Minimum request size: requests below a threshold are ignored to reduce
       amplification factor.
    """

    # Drop packets that are too small (reduces amplification factor)
    if len(data) < len(MAGIC) + 1:
        return None

    # Verify magic header
    if data[:4] != MAGIC:
        return None

    # Rate limit check
    if not rate_limiter.is_allowed(addr[0]):
        return make_error("rate limited")

    msg_type = data[4]
    payload = data[5:]

    if msg_type == MSG_CHALLENGE_REQUEST:
        # Step 1: Client requests a challenge token.
        # Request must include some padding to reduce amplification factor.
        # We require at least MIN_REQUEST_SIZE bytes total.
        if len(data) < MIN_REQUEST_SIZE:
            return None  # Silent drop - don't amplify tiny packets

        challenge_token = challenge_mgr.generate_challenge(addr)
        # Response: 4 magic + 1 type + 8 token = 13 bytes
        # Request was at least 32 bytes, so amplification factor < 1
        return make_response(MSG_CHALLENGE_RESPONSE, challenge_token)

    elif msg_type == MSG_STATUS_REQUEST:
        # Step 2: Client sends status request with challenge token.
        # Payload format: 8 bytes challenge token + 1 byte page number + padding
        if len(data) < MIN_REQUEST_SIZE:
            return None  # Silent drop

        if len(payload) < 8:
            return make_error("missing challenge")

        token = payload[:8]
        if not challenge_mgr.verify_challenge(addr, token):
            return make_error("invalid challenge")

        # Extract optional page number
        page = 0
        if len(payload) >= 9:
            page = payload[8]

        # Build paginated response to keep size bounded
        status_data = build_paginated_status(page, page_size=8)

        response = make_response(MSG_STATUS_RESPONSE, status_data)

        # Enforce maximum amplification factor of ~3x
        # (generous enough for legitimate use, but prevents abuse)
        max_allowed_response = len(data) * 3
        if len(response) > max_allowed_response:
            # Fall back to compact status
            compact_data = build_compact_status()
            response = make_response(MSG_STATUS_COMPACT, compact_data)
            # If still too large, truncate
            if len(response) > max_allowed_response:
                response = response[:max_allowed_response]

        return response

    else:
        # Unknown message type
        return None  # Silent drop for unknown types


def run_server():
    """Main server loop."""
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)

    # Set receive buffer size
    sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 65536)

    sock.bind((SERVER_HOST, SERVER_PORT))
    sock.settimeout(30.0)  # Timeout for periodic cleanup

    # Generate a random secret for challenge tokens
    import os
    secret = os.urandom(32)

    rate_limiter = RateLimiter(RATE_LIMIT_WINDOW, RATE_LIMIT_MAX_REQUESTS)
    challenge_mgr = ChallengeManager(secret, CHALLENGE_EXPIRY)

    last_cleanup = time.time()

    print(f"Game server status responder running on {SERVER_HOST}:{SERVER_PORT}")
    print(f"Anti-amplification measures active:")
    print(f"  - Challenge-response required for status queries")
    print(f"  - Rate limit: {RATE_LIMIT_MAX_REQUESTS} requests per {RATE_LIMIT_WINDOW}s per IP")
    print(f"  - Minimum request size: {MIN_REQUEST_SIZE} bytes")
    print(f"  - Maximum amplification factor: 3x")
    print(f"  - Paginated responses")

    while True:
        try:
            data, addr = sock.recvfrom(4096)

            response = handle_packet(data, addr, rate_limiter, challenge_mgr)

            if response is not None:
                sock.sendto(response, addr)
                print(
                    f"[{time.strftime('%H:%M:%S')}] {addr[0]}:{addr[1]} "
                    f"req={len(data)}B resp={len(response)}B "
                    f"ratio={len(response)/max(len(data),1):.1f}x"
                )
            else:
                print(
                    f"[{time.strftime('%H:%M:%S')}] {addr[0]}:{addr[1]} "
                    f"req={len(data)}B dropped"
                )

        except socket.timeout:
            pass
        except KeyboardInterrupt:
            print("\nShutting down server...")
            break
        except Exception as e:
            print(f"Error: {e}")

        # Periodic cleanup
        now = time.time()
        if now - last_cleanup > RATE_LIMIT_WINDOW * 2:
            rate_limiter.cleanup()
            last_cleanup = now

    sock.close()


def demo_client():
    """Demo client showing the challenge-response protocol."""
    import os

    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
    sock.settimeout(5.0)
    server_addr = ("127.0.0.1", SERVER_PORT)

    try:
        # Step 1: Request a challenge token
        # Pad the request to meet minimum size requirement
        challenge_request = MAGIC + struct.pack("B", MSG_CHALLENGE_REQUEST)
        padding_needed = max(0, MIN_REQUEST_SIZE - len(challenge_request))
        challenge_request += os.urandom(padding_needed)

        print(f"Sending challenge request ({len(challenge_request)} bytes)...")
        sock.sendto(challenge_request, server_addr)

        data, _ = sock.recvfrom(4096)
        if data[:4] != MAGIC or data[4] != MSG_CHALLENGE_RESPONSE:
            print(f"Unexpected response type: {data[4] if len(data) > 4 else 'N/A'}")
            return

        challenge_token = data[5:13]
        print(f"Received challenge token: {challenge_token.hex()}")

        # Step 2: Request status with challenge token
        for page in range(3):
            status_request = (
                MAGIC
                + struct.pack("B", MSG_STATUS_REQUEST)
                + challenge_token
                + struct.pack("B", page)
            )
            # Pad to minimum size
            padding_needed = max(0, MIN_REQUEST_SIZE - len(status_request))
            status_request += os.urandom(padding_needed)

            print(f"\nRequesting status page {page} ({len(status_request)} bytes)...")
            sock.sendto(status_request, server_addr)

            data, _ = sock.recvfrom(4096)
            if data[:4] != MAGIC:
                print("Invalid response")
                continue

            resp_type = data[4]
            resp_payload = data[5:]

            if resp_type == MSG_ERROR:
                print(f"Error: {resp_payload.decode('utf-8', errors='replace')}")
                break
            elif resp_type in (MSG_STATUS_RESPONSE, MSG_STATUS_COMPACT):
                status = json.loads(resp_payload.decode("utf-8"))
                print(f"Response ({len(data)} bytes):")
                print(json.dumps(status, indent=2))

                # Check if we've seen all pages
                if "total_pages" in status and page >= status["total_pages"] - 1:
                    print("\nAll pages retrieved.")
                    break

        # Demonstrate that a request without valid challenge fails
        print("\n--- Testing invalid challenge ---")
        bad_request = (
            MAGIC
            + struct.pack("B", MSG_STATUS_REQUEST)
            + b"\x00" * 8  # fake token
            + struct.pack("B", 0)
        )
        padding_needed = max(0, MIN_REQUEST_SIZE - len(bad_request))
        bad_request += os.urandom(padding_needed)

        sock.sendto(bad_request, server_addr)
        data, _ = sock.recvfrom(4096)
        if data[4] == MSG_ERROR:
            print(f"Expected error: {data[5:].decode('utf-8', errors='replace')}")

    except socket.timeout:
        print("Timeout waiting for response. Is the server running?")
    finally:
        sock.close()


